app.post(
  ["/vision/analyze", "/api/vision/analyze"],
  visionLimiter,
  upload.single("image"),
  async (req, res) => {
    try {
const uploadedObjectKey =
  safeStr(
    req.body?.imageKey ||
      req.body?.objectKey ||
      req.body?.scanAsset?.processedKey ||
      req.body?.scanAsset?.originalKey,
    320
  ) || null;

let file = req.file || null;

if (!file && uploadedObjectKey) {
  const objectBuffer = await objectStoreReadBuffer(uploadedObjectKey);

  if (Buffer.isBuffer(objectBuffer) && objectBuffer.length) {
    file = {
      fieldname: "image",
      originalname: path.basename(uploadedObjectKey),
      encoding: "7bit",
      mimetype: guessMimeFromKey(uploadedObjectKey),
      size: objectBuffer.length,
      buffer: objectBuffer,
    };
  }
}

      console.log("📸 VISION HIT", {
        rid: req.rid,
        path: req.originalUrl,
        hasFile: !!file,
        fileField: file?.fieldname || null,
        fileSize: file?.size || 0,
        bodyMode: req.body?.mode,
        contentType: req.headers["content-type"],
      });

      if (!file) {
        return res.status(200).json({
          ok: true,
          query: null,
          variants: [],
          confidence: 0,
          identity: null,
          visionIdentity: null,
          reason: "no_file_received",
        });
      }

      if (file.size < 4000) {
        return res.status(200).json({
          ok: true,
          query: null,
          variants: [],
          confidence: 0,
          identity: null,
          visionIdentity: null,
          reason: "image_too_small",
        });
      }

      console.log("✅ VISION FILE ACCEPTED", {
        rid: req.rid,
        size: file.size,
        mimetype: file.mimetype,
      });

// Phase 4: compute scan embedding
let scanEmbedding = null;
let visualMatches = [];

if (!openai) {
  return res.status(200).json({
    ok: true,
    query: null,
    variants: [],
    confidence: 0,
    identity: null,
    visionIdentity: null,
    reason: "missing_openai_api_key",
  });
}

      if (visionCoolingDown()) {
        console.warn("⚠️ Vision temporarily disabled (cooldown active)");
        return res.status(200).json({
          ok: true,
          query: null,
          variants: [],
          confidence: 0,
          identity: null,
          visionIdentity: null,
          reason: "vision_rate_limited",
        });
      }

      const mode = cleanMode(req.body?.mode);
      const rawPropContext = safeStr(req.body?.propContext, 220);
      const originalPrice = Number(req.body?.originalPrice || req.body?.price || 0) || null;
      const cheapestAlt = Number(req.body?.cheapestAlternative || req.body?.cheapestAlt || 0) || null;
      const itemHint = typeof req.body?.itemHint === "string" ? req.body.itemHint.trim().slice(0, 80) : null;
      const priceRef = originalPrice || cheapestAlt;
      const priceBracket = priceRef
        ? priceRef >= 500 ? "luxury"
        : priceRef >= 150 ? "premium"
        : priceRef >= 50  ? "mid"
        : "entry"
        : null;
      const priceContext = priceBracket
        ? `price:${priceBracket}|listed:${originalPrice || "?"}|alt:${cheapestAlt || "?"}`
        : "";
      const hintContext = itemHint ? `hint:${itemHint}` : "";
      const propContext = [rawPropContext, priceContext, hintContext].filter(Boolean).join("|");
      const imgHash = sha256(file.buffer);
      const cacheKey = `vision|consensus|${mode}|${propContext}|${imgHash}`;

      let cached = await cacheGet(cacheKey);
      if (!cached) cached = visionCache.get(cacheKey);

      if (cached) {
        return res.status(200).json({ ...cached, cached: true });
      }

      const originalHash = imgHash;

      // Preprocess synchronously (needed for vision API call)
      // Storage writes fire in background — don't block the vision call
      const processed = await preprocessScanUpload(file).catch(() => ({
        buffer: file.buffer,
        mimetype: file.mimetype || "image/jpeg",
        thumbnailBuffer: null,
        thumbnailMime: null,
        quality: null,
        metadata: { transformed: false, size: file.buffer.length, originalSize: file.buffer.length },
      }));

      const preparedFile = {
        ...file,
        buffer: processed.buffer,
        mimetype: processed.mimetype,
        size: processed.buffer.length,
      };

      // Fire storage persistence in background — vision doesn't need to wait
      enqueueBackgroundJob(
        "persist_scan_artifacts",
        { imageHash: originalHash },
        async () => {
          try {
            await persistScanArtifacts(file, originalHash);
          } catch (e) {
            console.warn("persist_scan_artifacts_bg_error", e?.message || e);
          }
          return { ok: true };
        }
      );

      // Build a lightweight storedScan-compatible object for downstream code
      const storedScan = {
        imageHash: originalHash,
        asset: {
          hash: originalHash,
          originalKey: null,
          processedKey: null,
          thumbKey: null,
          manifestKey: null,
          originalUrl: null,
          processedUrl: null,
          thumbUrl: null,
        },
        preprocess: {
          ...processed.metadata,
          quality: processed.quality || null,
        },
        processedBuffer: processed.buffer,
        processedMime: processed.mimetype,
      };

      const requestPlan = getResolvedPlan(req);
      const imageQuality = processed?.quality || null;

      if (imageQuality?.usable === false && requestPlan !== "internal") {
        return res.status(200).json({
          ok: true,
          query: null,
          variants: [],
          confidence: 0,
          identity: null,
          visionIdentity: null,
          imageHash: originalHash,
          scanAsset: storedScan.asset,
          preprocess: storedScan.preprocess,
          reason: "image_quality_low",
        });
      }

      const visionCostUnits = requestPlan === "free" ? 1 : 2;
      const canSpendVision = await sourceBudget.canUse("vision", {
        plan: requestPlan,
        costUnits: visionCostUnits,
      });

      if (!canSpendVision) {
        return res.status(200).json({
          ok: true,
          query: null,
          variants: [],
          confidence: 0,
          identity: null,
          visionIdentity: null,
          imageHash: originalHash,
          scanAsset: storedScan.asset,
          preprocess: storedScan.preprocess,
          reason: "vision_budget_exhausted",
        });
      }

      await sourceBudget.note("vision", {
        costUnits: visionCostUnits,
      });

      const allowFreshEmbedding =
        requestPlan === "pro" || requestPlan === "internal";

      // Embedding runs in background after response — never blocks the scan result
      const embeddingPromise = Promise.resolve({ scanEmbedding: null, visualMatches: [] });

      console.log("🧠 CALLING OPENAI VISION", {
        rid: req.rid,
        mode,
        model: VISION_MODEL,
        imageHash: originalHash,
      });

      global.metrics.visionCalls++;

      const result = await withInflight(cacheKey, async () =>
        distributedSingleflight.run(
          `vision:${mode}:${propContext}:${originalHash}`,
          async () =>
            visionConcurrency(async () =>
              withHardTimeout(
                runVisionConsensus({
                  req,
                  file: preparedFile,
                  mode,
                  propContext,
                }),
                20000,
                "vision_consensus_timeout"
              )
            )
        )
      );

      // Embedding is background-only; scanEmbedding/visualMatches stay null for immediate response
      scanEmbedding = null;
      visualMatches = [];

      // Fire embedding in background after response
      if (allowFreshEmbedding) {
        enqueueBackgroundJob(
          "scan_embedding",
          { imageHash: originalHash },
          async () => {
            try {
              const vector = await getOrCreateStoredEmbedding(originalHash, processed.buffer);
              if (vector) {
                const q = result?.query || null;
                if (q) storeVector(q, vector);
                await upsertScanVector({
                  imageHash: originalHash,
                  query: q,
                  vector,
                  metadata: { imageHash: originalHash },
                }).catch(() => {});
              }
            } catch (e) {
              console.warn("bg_embedding_error", e?.message || e);
            }
            return { ok: true };
          }
        );
      }

       const shaped = {
          ok: true,
          query: result?.query || null,
          variants: Array.isArray(result?.variants) ? result.variants : [],
          confidence: clamp01(Number(result?.confidence || 0)),
          identity: {
            ...(result?.identity || {}),
            imageHash: originalHash,
          },
          visionIdentity: {
            ...(result?.identity || {}),
            imageHash: originalHash,
          },
          imageHash: originalHash,
          scanAsset: storedScan.asset,
          preprocess: storedScan.preprocess,
          visualMatches,
          attributeCertainty: result?.attributeCertainty
            ? buildAttributeCertaintyPayload(result.attributeCertainty)
            : null,
          authenticityFlags: Array.isArray(result?.authenticityFlags) ? result.authenticityFlags : [],
          conditionFlags:    Array.isArray(result?.conditionFlags)    ? result.conditionFlags    : [],
          debug: result?.debug || null,
        };

        // ── Serial parser (non-LLM, from visibleText) ──────────────────────────
        const visibleTextArray = Array.isArray(shaped.identity?.visibleText)
          ? shaped.identity.visibleText
          : [];
        let serialResult = null;
        if (visibleTextArray.length) {
          try {
            serialResult = await parseSerialFromText(visibleTextArray, redis);
            if (serialResult?.ok) {
              shaped.serialResult = serialResult;
            }
          } catch (e) {
            console.warn("serial_parser_text_error", e?.message || e);
          }
        }

        // ── Condition grader ───────────────────────────────────────────────────
        try {
          const conditionGrade = gradeCondition({
            visionResult:      shaped,
            category:          shaped.identity?.category || null,
            overallConfidence: shaped.confidence,
          });
          shaped.conditionGrade = conditionGrade;
        } catch (e) {
          console.warn("condition_grader_error", e?.message || e);
        }

        // ── Resale graph ingest (background) ───────────────────────────────────
        if (shaped.identity && shaped.query) {
          enqueueBackgroundJob(
            "graph_ingest",
            { imageHash: originalHash, query: shaped.query },
            async () => {
              try {
                await ingestScanToGraph(redis, {
                  identity:    shaped.identity,
                  marketItems: [],
                  serialResult: serialResult || null,
                });
              } catch (e) {
                console.warn("graph_ingest_error", e?.message || e);
              }
              return { ok: true };
            }
          );
        }

        // ── Counterfactual scan (pro/internal only, background) ─────────────────
        if (
          (requestPlan === "pro" || requestPlan === "internal") &&
          shaped.query &&
          process.env.COUNTERFACTUAL_ENABLED !== "false"
        ) {
          const base64ForCF    = preparedFile.buffer.toString("base64");
          const dataUrlForCF   = `data:${preparedFile.mimetype || "image/jpeg"};base64,${base64ForCF}`;
          enqueueBackgroundJob(
            "counterfactual_scan",
            { imageHash: originalHash, query: shaped.query },
            async () => {
              try {
                const cfResult = await runCounterfactualScan({
                  dataUrl:       dataUrlForCF,
                  mode,
                  propContext,
                  rid:           req.rid,
                  primaryResult: result,
                  marketItems:   [],
                  plan:          requestPlan,
                  runVisionPassFn: runVisionPass,
                });
                if (cfResult) {
                  // Cache counterfactual result separately, frontend can poll /vision/counterfactual/:hash
                  await cacheSet(
                    `counterfactual:${originalHash}`,
                    cfResult,
                    3600
                  );
                }
              } catch (e) {
                console.warn("counterfactual_error", e?.message || e);
              }
              return { ok: true };
            }
          );
        }



      if (scanEmbedding && shaped.query) {

        enqueueBackgroundJob(
          "store_scan_vector",
          {
            imageHash: originalHash,
            query: shaped.query,
          },
          async () => {
            storeVector(shaped.query, scanEmbedding);

            await upsertScanVector({
              imageHash: originalHash,
              query: shaped.query,
              vector: scanEmbedding,
              metadata: {
                imageHash: originalHash,
                identity: shaped.identity || null,
                preprocess: shaped.preprocess || null,
              },
            });

            return {
              ok: true,
              imageHash: originalHash,
              query: shaped.query,
            };
          }
        );
      }

        // ── Barcode Intelligence (Feature 63) ─────────────────────────────────
        try {
          const barcodeResult = await buildBarcodeIntelligencePayload({
            visibleText: Array.isArray(shaped.identity?.visibleText) ? shaped.identity.visibleText : [],
            barcode:     req.body?.barcode || null,
            redis,
          });
          shaped.barcodeIntel = barcodeResult;
          // If barcode found a product and we have no query, use barcode query
          if (barcodeResult?.found && barcodeResult.query && !shaped.query) {
            shaped.query = barcodeResult.query;
          }
          // Upgrade identity with barcode brand/model if vision was uncertain
          if (barcodeResult?.found && shaped.confidence < 0.6) {
            if (barcodeResult.brand && !shaped.identity?.brand) shaped.identity.brand = barcodeResult.brand;
            if (barcodeResult.title && !shaped.identity?.model) shaped.identity.model = barcodeResult.title;
          }
        } catch (e) { console.warn("barcode_intel_error", e?.message || e); }

        // ── Box Tag Extraction (Feature 65) ────────────────────────────────────
        try {
          const boxTagResult = buildBoxTagPayload({
            visibleText: Array.isArray(shaped.identity?.visibleText) ? shaped.identity.visibleText : [],
            identity:    shaped.identity || {},
            query:       shaped.query,
          });
          shaped.boxTag = boxTagResult;
          // Upgrade query with SKU/colorway info from box tag
          if (boxTagResult?.hasBoxData && boxTagResult.enhancedQuery) {
            shaped.identity.exactQuery = boxTagResult.enhancedQuery;
            if (!shaped.identity.sizeHint && boxTagResult.boxTag?.size) {
              shaped.identity.sizeHint = boxTagResult.boxTag.size;
            }
          }
        } catch (e) { console.warn("box_tag_error", e?.message || e); }

        // ── Logo Confidence Scoring (Feature 67) ──────────────────────────────
        try {
          const logoConf = buildLogoConfidencePayload(shaped);
          shaped.logoConfidence = logoConf?.logoConfidence || null;
          // If logo confidence says brand is NOT trusted, lower overall confidence
          if (logoConf?.logoConfidence?.trusted === false && shaped.confidence > 0.6) {
            shaped.confidence = Math.max(0.35, shaped.confidence - 0.20);
            shaped.attributeCertainty = {
              ...(shaped.attributeCertainty || {}),
              brand: Math.min(shaped.attributeCertainty?.brand ?? 0.5, 0.5),
            };
          }
        } catch (e) { console.warn("logo_confidence_error", e?.message || e); }

        // ── Accuracy Firewall — query de-hallucination ─────────────────────────
        // When vision confidence is low (<0.55), strip over-specific terms that
        // are likely hallucinated: colorway names in quotes, edition years,
        // specific SKU fragments that weren't in visible text.
        try {
          const firewall = queryAccuracyFirewall(shaped);
          if (firewall.stripped) {
            shaped.query = firewall.safeQuery;
            shaped.identity.exactQuery = firewall.safeQuery;
            shaped.firewallStripped = firewall.stripped;
            console.log("🛡️ Accuracy firewall stripped hallucinated specificity:", {
              original: firewall.originalQuery,
              safe: firewall.safeQuery,
              confidence: firewall.confidence,
            });
          }
        } catch (e) { /* non-fatal */ }

        // ── Seller Jargon Normalization (Feature 66) ──────────────────────────
        try {
          if (shaped.query) {
            const jargonResult = normalizeSellerJargon(shaped.query);
            if (jargonResult.changed && jargonResult.normalized) {
              shaped.normalizedQuery = jargonResult.normalized;
              shaped.jargonExtracted = jargonResult.extracted;
            }
          }
        } catch (e) { console.warn("jargon_normalizer_error", e?.message || e); }

        // ── Scan replay recording (background) ────────────────────────────────
        if (process.env.SCAN_REPLAY_ENABLED !== "false") {
          queueScanReplayRecord({
            scanId:            originalHash,
            userId:            getResolvedUserId(req) || null,
            imageHash:         originalHash,
            query:             shaped.query,
            visionResult:      { confidence: shaped.confidence, identity: shaped.identity },
            serialResult:      shaped.serialResult  || null,
            conditionGrade:    shaped.conditionGrade || null,
            attributeCertainty:result?.attributeCertainty || null,
            marketItems:       [],
            mode,
            plan:              requestPlan,
          });
        }

        // ── Price intelligence (zero-cost, from user inputs) ────────────────────
        if (originalPrice || cheapestAlt) {
          const intel = { priceBracket: priceBracket || null };
          if (originalPrice) intel.listedPrice = originalPrice;
          if (cheapestAlt)   intel.cheapestAlt  = cheapestAlt;
          if (originalPrice && cheapestAlt && cheapestAlt > 0) {
            const savingsPct = ((cheapestAlt - originalPrice) / cheapestAlt * 100);
            const roundedPct = Math.abs(Math.round(savingsPct * 10) / 10);
            intel.savingsVsAlt       = Math.round(savingsPct * 10) / 10;
            intel.isCheaperThanAlt   = originalPrice < cheapestAlt;
            intel.signal = intel.isCheaperThanAlt
              ? `Listed ${roundedPct}% below cheapest alternative ($${cheapestAlt})`
              : `Listed ${roundedPct}% above cheapest alternative ($${cheapestAlt})`;
          }
          shaped.priceIntelligence = intel;
        }

        // ── Institutional Bridge: Signal Fingerprint Map ─────────────────────────
        // Generates raw_evidence_hash (Phase 7 anchor), institutionalIds,
        // autoCropRequired, progressToken, and verificationReady flag.
        try {
          const signalMap = buildSignalMap(
            {
              ...result,
              institutionalIds: result?.institutionalIds || null,
            },
            {
              imageHash: originalHash,
              mode,
              passCount: 2,
            }
          );
          shaped.signalMap       = signalMap;
          shaped.rawEvidenceHash = signalMap.rawEvidenceHash || null;
          shaped.progressToken   = signalMap.progressToken   || "IMAGE_ANALYZED";
          shaped.autoCropRequired= signalMap.autoCropRequired || false;
          shaped.autoCropReason  = signalMap.autoCropReason  || null;
          shaped.verificationReady = signalMap.verificationReady || false;
          // Lift institutionalIds to top level for Phase 7/8 direct consumption
          if (signalMap.institutionalIds) {
            shaped.institutionalIds = signalMap.institutionalIds;
          }
        } catch (e) { console.warn("signal_fingerprint_error", e?.message || e); }

        // ── Institutional Bridge: Platform Fee Payload ───────────────────────────
        // Pre-computes category-specific platform fees for Phase 10 P&L engine.
        // Uses originalPrice (user's stated price) as the anchor.
        try {
          const feePrice = originalPrice || null;
          if (feePrice) {
            shaped.platformFeePayload = buildPlatformFeePayload({
              price:    feePrice,
              category: shaped.identity?.category || null,
            });
          }
        } catch (e) { console.warn("platform_fee_error", e?.message || e); }

        visionCache.set(cacheKey, shaped);
        await cacheSet(cacheKey, shaped, 86400);

        return res.status(200).json(shaped);
    } catch (err) {
      if (err?.status === 429 || String(err?.message || "").includes("429")) {
        triggerVisionCooldown(60);
      }

      const name = err?.name || "error";
      const reason = name === "AbortError" ? "vision_timeout" : "vision_exception";

      incrementMetric("vision_failure_total", {
        reason,
      });

      await emitOpsAlert(
        "vision_failure",
        {
          rid: req.rid,
          reason,
          message: err?.message || String(err),
          route: req.originalUrl,
        },
        {
          severity: reason === "vision_timeout" ? "warn" : "error",
          cooldownMs: 60_000,
        }
      );

      console.warn("❌ VISION ERROR:", reason, err?.message || err, err?.stack?.split("\n").slice(1,4).join(" | "));

      return res.status(200).json({
        ok: true,
        query: null,
        variants: [],
        confidence: 0,
        identity: null,
        visionIdentity: null,
        reason,
      });
    }
  }
);

