app.post("/vision/enrich", async (req, res) => {
  try {
    if (!openai) return res.status(200).json({ ok: false, reason: "missing_openai_api_key" });


    const rawQuery = safeStr(req.body?.query, 220);
    const query = normalizeQuery(rawQuery);
    const mode = cleanMode(req.body?.mode);
    const context = safeStr(req.body?.context, 220);

    if (!query) return res.status(200).json({ ok: false, reason: "missing_query" });

    const cacheKey = `enrich2|${mode}|${context}|${query}`;
    const cached = visionCache.get(cacheKey);
    if (cached) return res.status(200).json({ ...cached, cached: true });

    const enrichPrompt = `
You are Evan AI — world-class resale intelligence enrichment engine.
You are given a marketplace search query and must return the richest, most accurate resale-relevant structured data possible.

Input query: "${query}"
Mode: "${mode}"
Context: "${context || "none"}"

Your output powers a resale intelligence app used by buyers and flippers. Be a domain expert:

COLLECTOR block — identify the item's collector and resale significance:
- summary: 1-2 sentence expert description (brand, model, era, why it matters to resellers)
- era: decade or specific year range if known (e.g. "2019-2022", "1990s", "2015 retro")
- maker: exact brand/manufacturer name (canonical spelling, e.g. "Louis Vuitton", "Nike", "Rolex")
- model: exact model name as used in marketplace listings (e.g. "Air Jordan 1 Retro High OG", "Neverfull MM", "Submariner Date")
- tells: array of 3-6 authenticity visual tells or collector knowledge facts (e.g. "heel tab should read NIKE AIR", "LV date code format: 2 letters + 4 digits", "Rolex cyclops magnifies date 2.5x")

MATERIALS block — signals: array of material/construction signals that affect value (e.g. "full-grain leather", "canvas upper", "YKK zipper", "sapphire crystal", "titanium case")

ALTERNATIVES block — queries: array of 4-8 alternative marketplace search queries covering:
- narrower searches (add colorway, size, year)
- broader searches (remove specifics)
- alternate names/spellings used by sellers
- related collab or special editions that fetch similar prices

LOCAL block — keywords: 4-6 search terms optimized for local marketplace apps (OfferUp, Facebook Marketplace) — simpler, broader, common vernacular

PARTS block — keywords: 4-6 keywords for parts/accessories/replacement searches (e.g. "Air Jordan 1 replacement laces", "Rolex jubilee bracelet", "Louis Vuitton Neverfull insert")

PRICE_RANGE block — typical resale price range on secondary market (eBay sold listings, StockX, etc.):
- low: conservative floor price in USD (recent sold comps, worn/fair condition)
- high: ceiling price in USD (recent sold comps, new/excellent condition)
- typical: most common sold price for average condition
- currency: "USD"
- note: brief justification or caveat (e.g. "varies by colorway", "size-dependent", "authentication required")

Be specific. Be accurate. This data is used to find real resale prices — wrong data = financial harm.
`.trim();

    const timeout = withTimeout(TEXT_TIMEOUT_MS);

    const response = await withModelServing(
      "vision_enrich",
      () =>
        openai.responses.create(
          {
            model: ENRICH_MODEL,
            temperature: 0.2,
            max_output_tokens: 800,

            prompt_cache_key: "evan-ai-enrich-v6",
            prompt_cache_retention: "24h",

            text: {
              format: {
                type: "json_schema",
                name: "evan_ai_enrich_result",
                strict: true,
                schema: {
                  type: "object",
                  additionalProperties: false,
                  required: ["ok", "collector", "materials", "alternatives", "local", "parts", "priceRange"],
                  properties: {
                    ok: { type: "boolean" },
                    collector: {
                      type: "object",
                      additionalProperties: false,
                      required: ["summary", "era", "maker", "model", "tells"],
                      properties: {
                        summary: { anyOf: [{ type: "string" }, { type: "null" }] },
                        era: { anyOf: [{ type: "string" }, { type: "null" }] },
                        maker: { anyOf: [{ type: "string" }, { type: "null" }] },
                        model: { anyOf: [{ type: "string" }, { type: "null" }] },
                        tells: { type: "array", items: { type: "string" } },
                      },
                    },
                    materials: {
                      type: "object",
                      additionalProperties: false,
                      required: ["signals"],
                      properties: {
                        signals: { type: "array", items: { type: "string" } },
                      },
                    },
                    alternatives: {
                      type: "object",
                      additionalProperties: false,
                      required: ["queries"],
                      properties: {
                        queries: { type: "array", items: { type: "string" } },
                      },
                    },
                    local: {
                      type: "object",
                      additionalProperties: false,
                      required: ["keywords"],
                      properties: {
                        keywords: { type: "array", items: { type: "string" } },
                      },
                    },
                    parts: {
                      type: "object",
                      additionalProperties: false,
                      required: ["keywords"],
                      properties: {
                        keywords: { type: "array", items: { type: "string" } },
                      },
                    },
                    priceRange: {
                      type: "object",
                      additionalProperties: false,
                      required: ["low", "high", "typical", "currency", "note"],
                      properties: {
                        low:      { anyOf: [{ type: "number" }, { type: "null" }] },
                        high:     { anyOf: [{ type: "number" }, { type: "null" }] },
                        typical:  { anyOf: [{ type: "number" }, { type: "null" }] },
                        currency: { type: "string" },
                        note:     { anyOf: [{ type: "string" }, { type: "null" }] },
                      },
                    },
                  },
                },
              },
            },

            input: [{ role: "user", content: [{ type: "input_text", text: enrichPrompt }] }],
            metadata: { rid: req.rid || "", mode: mode || "item" },
          },
          { signal: timeout.signal }
        ),
      {
        provider: "openai",
        model: ENRICH_MODEL,
        maxConsecutiveFailures: 4,
        circuitMs: 45_000,
      }
    );
    timeout.cancel();

    let parsed = null;
    try {
      const rawEnrich = typeof response?.output_text === "string"
        ? response.output_text
        : response?.choices?.[0]?.message?.content || "{}";
      parsed = JSON.parse(rawEnrich || "{}");
    } catch {
      parsed = null;
    }

    if (!parsed || parsed.ok !== true) {
      return res.status(200).json({ ok: false, reason: "parse_failed" });
    }

    visionCache.set(cacheKey, parsed);
    return res.status(200).json(parsed);
  } catch (e) {
    return res.status(200).json({ ok: false, reason: "enrich_exception" });
  }
});




// -------------------- SERP: google shopping --------------------
async function serpShopping(query, opts = {}) {
  const { bypassCooldown = false, softFail = false } = opts || {};

  if (!SERPAPI_KEY) return [];
  if (process.env.DISABLE_SERP === "true") return [];
  if (!bypassCooldown && isSourceCoolingDown("serpapi")) {
  console.warn("⚠️ SerpAPI cooling — allowing fallback queries");
}


  const startedAt = Date.now();

  const params = new URLSearchParams({
    engine: "google_shopping",
    q: query,
    hl: "en",
    gl: "us",
    api_key: SERPAPI_KEY,
  });

  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 12000);

  try {
    const url = `https://serpapi.com/search.json?${params.toString()}`;
    const r = await fetch(url, { signal: controller.signal });

      if (!r.ok) {
        if (r.status === 429) {
          if (!softFail) {
            markSourceFailure("serpapi", "http_429");

            const h = getSourceHealth("serpapi");
            h.cooldownUntil = Math.max(
              Number(h.cooldownUntil || 0),
              Date.now() + 45 * 1000
            );
          }

          console.warn(
            "⚠️ SerpAPI 429.",
            softFail ? "Skipping secondary query." : "Cooling down source for 45s.",
            "query=",
            query,
            "softFail=",
            softFail
          );
          return [];
        }

      if (!softFail) {
        markSourceFailure("serpapi", `http_${r.status}`);
      }

      console.warn(
        "⚠️ SerpAPI request failed:",
        r.status,
        "query=",
        query,
        "softFail=",
        softFail
      );
      return [];
    }

    const data = await r.json();

    const raw = [
      ...(Array.isArray(data.shopping_results) ? data.shopping_results : []),
      ...(Array.isArray(data.inline_shopping_results)
        ? data.inline_shopping_results
        : []),
    ];

    console.log("🛒 SERP RAW COUNT", {
      query,
      raw: raw.length,
      hasShoppingResults: Array.isArray(data.shopping_results),
      hasInlineShoppingResults: Array.isArray(data.inline_shopping_results),
    });

    let items = raw
      .map((it, idx) => {
        const normalized = normalizeItem({
          ...it,
          link:
            it.link ||
            it.product_link ||
            it.product_page_url ||
            it.google_product_link ||
            it.google_shopping_product_link ||
            it.offer_page_url ||
            it.offer_link ||
            it.merchant_link ||
            it.product_url ||
            it.url ||
            it.serpapi_link ||
            null,
        });

        const fallbackLink =
          normalized.link ||
          normalized.googleProductLink ||
          normalized.merchantLink ||
          it.link ||
          it.product_link ||
          it.product_page_url ||
          it.google_product_link ||
          it.google_shopping_product_link ||
          it.offer_page_url ||
          it.offer_link ||
          it.merchant_link ||
          it.product_url ||
          it.url ||
          it.serpapi_link ||
          null;

        return {
          ...normalized,
          link: fallbackLink,
          url: fallbackLink,
          buyLink: fallbackLink,
          linkVerified: Boolean(fallbackLink),
          source:
            normalized.source ||
            it.source ||
            it.store_name ||
            it.store ||
            it.seller ||
            it.merchant_name ||
            "google shopping",
          __fromMarketSearch: true,
          __serverRank: idx + 1,
        };
      })
      .filter((x) => x.title)
      .filter(
        (x) => Number.isFinite(x.totalPrice) || Number.isFinite(x.price)
      );

    items = dedupeSmart(items);

    console.log("🛒 SERP NORMALIZED COUNT", {
      query,
      raw: raw.length,
      kept: items.length,
      top: items.slice(0, 3).map((x) => ({
        title: x.title,
        price: x.totalPrice ?? x.price ?? null,
        link: x.link || null,
        source: x.source || null,
      })),
    });

    markSourceSuccess("serpapi", Date.now() - startedAt);

    // IMPORTANT:
    // keep serpShopping relaxed.
    // mergeCheapestSources already does the smarter filtering/ranking later.
    return items.slice(0, 60);
  } catch (err) {
    if (!softFail) {
      markSourceFailure(
        "serpapi",
        err?.name === "AbortError" ? "timeout" : "exception"
      );
    }

    console.warn(
      "⚠️ SerpAPI search error:",
      err?.name || "error",
      err?.message || err,
      "query=",
      query,
      "softFail=",
      softFail
    );

    return [];
  } finally {
    clearTimeout(t);
  }
}

// -------------------- SERP: eBay Sold Comps (Feature 4) --------------------
// Fetches eBay *completed/sold* listings via SerpAPI eBay engine.
// Returns an array of sold comp objects: { title, soldPrice, soldDate, condition, url }
async function serpEbaySold(query) {
  if (!SERPAPI_KEY) return [];
  if (process.env.DISABLE_SERP === "true") return [];
  if (isSourceCoolingDown("serpapi")) return [];

  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 12000);

  try {
    // SerpAPI eBay engine: _nkw = keyword, LH_Complete=1 & LH_Sold=1 via ebay params
    const params = new URLSearchParams({
      engine: "ebay",
      _nkw: query,
      ebay_domain: "ebay.com",
      LH_Complete: "1",  // Completed listings
      LH_Sold: "1",       // Sold listings only
      _sop: "13",         // Sort by most recent first
      api_key: SERPAPI_KEY,
    });

    const url = `https://serpapi.com/search.json?${params.toString()}`;
    const r = await fetch(url, { signal: controller.signal });

    if (!r.ok) {
      if (r.status === 429) {
        const h = getSourceHealth("serpapi");
        h.cooldownUntil = Math.max(Number(h.cooldownUntil || 0), Date.now() + 45 * 1000);
      }
      return [];
    }

    const data = await r.json();
    const raw = Array.isArray(data.organic_results) ? data.organic_results : [];

    const comps = raw
      .filter((it) => it?.price?.raw || it?.price?.extracted || it?.prices?.[0]?.raw)
      .slice(0, 25)
      .map((it) => {
        const priceRaw = it?.price?.extracted ?? it?.prices?.[0]?.extracted ?? 0;
        const price = Number(priceRaw) || 0;
        return {
          title: String(it?.title || "").slice(0, 120),
          soldPrice: price,
          soldDate: it?.date?.human_date || it?.date?.raw || null,
          condition: it?.condition || null,
          url: it?.link || null,
          shipping: it?.shipping?.extracted ?? null,
          totalPrice: price + (Number(it?.shipping?.extracted) || 0),
        };
      })
      .filter((c) => c.soldPrice > 0);

    if (comps.length) {
      const prices = comps.map((c) => c.totalPrice || c.soldPrice);
      prices.sort((a, b) => a - b);
      const mid = Math.floor(prices.length / 2);
      const median = prices.length % 2 === 0
        ? (prices[mid - 1] + prices[mid]) / 2
        : prices[mid];

      // ── Velocity computation ────────────────────────────────────────────
      // Parse soldDate strings into timestamps. SerpAPI gives either:
      //   • Absolute: "Jan 15, 2026" / "February 2, 2026"
      //   • Relative: "2 days ago" / "1 week ago"
      const parseSoldDate = (str) => {
        if (!str || typeof str !== "string") return null;
        const s = str.trim();
        const now = Date.now();
        // Relative
        const rel = s.match(/^(\d+)\s*(hour|day|week|month)/i);
        if (rel) {
          const n   = parseInt(rel[1], 10);
          const u   = rel[2].toLowerCase();
          const ms  = u.startsWith("hour")  ? n * 3_600_000
                    : u.startsWith("day")   ? n * 86_400_000
                    : u.startsWith("week")  ? n * 7 * 86_400_000
                    : u.startsWith("month") ? n * 30 * 86_400_000 : 0;
          return ms ? new Date(now - ms) : null;
        }
        // Absolute
        const d = new Date(s);
        return isNaN(d.getTime()) ? null : d;
      };

      const now = Date.now();
      const MS_30D = 30 * 86_400_000;
      const parsedDates = comps.map((c) => parseSoldDate(c.soldDate)).filter(Boolean);

      // How many sold in last 30 days
      const soldCount30d = parsedDates.length
        ? parsedDates.filter((d) => now - d.getTime() <= MS_30D).length
        : 0;

      // Avg days to sell: spread oldest → newest divided by count
      let avgDaysToSell = null;
      if (parsedDates.length >= 2) {
        const oldest = Math.min(...parsedDates.map((d) => d.getTime()));
        const span   = (now - oldest) / 86_400_000; // days
        avgDaysToSell = Math.max(1, Math.round(span / parsedDates.length));
      }

      // Velocity tier (use soldCount30d if we have dates, else fall back to total count)
      const velocityCount = parsedDates.length ? soldCount30d : comps.length;
      const velocityTier  = velocityCount >= 18 ? "hot"
                          : velocityCount >= 10 ? "active"
                          : velocityCount >= 5  ? "steady"
                          : velocityCount >= 2  ? "slow"
                          : "rare";

      const velocityLabel = { hot: "Hot", active: "Active", steady: "Steady", slow: "Slow", rare: "Rare" }[velocityTier];

      console.log("🏷️ EBAY SOLD COMPS", {
        query,
        count: comps.length,
        low: prices[0],
        median: Math.round(median),
        high: prices[prices.length - 1],
        soldCount30d,
        avgDaysToSell,
        velocityTier,
      });

      return {
        comps,
        count: comps.length,
        low: prices[0],
        median: Math.round(median * 100) / 100,
        high: prices[prices.length - 1],
        avg: Math.round((prices.reduce((s, p) => s + p, 0) / prices.length) * 100) / 100,
        recentSolds: comps.slice(0, 5),
        // Velocity fields
        soldCount30d:   soldCount30d || comps.length,  // fall back to total count
        avgDaysToSell,
        velocityTier,
        velocityLabel,
        hasDates: parsedDates.length > 0,
      };
    }

    return null;
  } catch (err) {
    if (err?.name !== "AbortError") {
      console.warn("⚠️ serpEbaySold error:", err?.message || err, "query=", query);
    }
    return null;
  } finally {
    clearTimeout(t);
  }
}

// -------------------- SERP: Local / Hyperlocal Shopping (Feature 5) --------------------
// Fetches Google Shopping results filtered to a geographic area via location string.
// Returns { low, median, high, avg, count, items[] } or null.
async function serpLocalShopping(query, location) {
  if (!SERPAPI_KEY) return null;
  if (process.env.DISABLE_SERP === "true") return null;
  if (!location) return null;
  if (isSourceCoolingDown("serpapi")) return null;

  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 12000);

  try {
    const params = new URLSearchParams({
      engine: "google_shopping",
      q: `${query} near me`,
      hl: "en",
      gl: "us",
      location: location, // e.g. "10001" zip or "New York, NY"
      api_key: SERPAPI_KEY,
    });

    const url = `https://serpapi.com/search.json?${params.toString()}`;
    const r = await fetch(url, { signal: controller.signal });

    if (!r.ok) {
      if (r.status === 429) {
        const h = getSourceHealth("serpapi");
        h.cooldownUntil = Math.max(Number(h.cooldownUntil || 0), Date.now() + 45 * 1000);
      }
      return null;
    }

    const data = await r.json();
    const raw = [
      ...(Array.isArray(data.shopping_results) ? data.shopping_results : []),
      ...(Array.isArray(data.inline_shopping_results) ? data.inline_shopping_results : []),
    ];

    const items = raw
      .filter((it) => it?.price)
      .slice(0, 20)
      .map((it) => {
        const price = Number(String(it.price || "0").replace(/[^0-9.]/g, "")) || 0;
        const shipping = Number(String(it?.delivery || "0").replace(/[^0-9.]/g, "")) || 0;
        return {
          title: String(it?.title || "").slice(0, 100),
          price,
          shipping,
          totalPrice: price + shipping,
          source: it?.source || it?.merchant?.name || "local",
          thumbnail: it?.thumbnail || null,
        };
      })
      .filter((it) => it.price > 0);

    if (!items.length) return null;

    const prices = items.map((it) => it.totalPrice || it.price).sort((a, b) => a - b);
    const mid = Math.floor(prices.length / 2);
    const median = prices.length % 2 === 0
      ? (prices[mid - 1] + prices[mid]) / 2
      : prices[mid];

    console.log("📍 LOCAL SHOPPING COMPS", {
      query, location,
      count: items.length,
      low: prices[0],
      median: Math.round(median),
    });

    return {
      location,
      count: items.length,
      low: prices[0],
      median: Math.round(median * 100) / 100,
      high: prices[prices.length - 1],
      avg: Math.round((prices.reduce((s, p) => s + p, 0) / prices.length) * 100) / 100,
      items: items.slice(0, 8),
    };
  } catch (err) {
    if (err?.name !== "AbortError") {
      console.warn("⚠️ serpLocalShopping error:", err?.message || err, "query=", query);
    }
    return null;
  } finally {
    clearTimeout(t);
  }
}

// -------------------- SERP: Amazon --------------------
async function serpAmazon(query, opts = {}) {
  const { bypassCooldown = false, softFail = false } = opts || {};

  if (!SERPAPI_KEY) return [];
  if (process.env.DISABLE_SERP === "true") return [];
  if (!bypassCooldown && isSourceCoolingDown("serpapi")) return [];

  const startedAt = Date.now();

  const params = new URLSearchParams({
    engine: "amazon",
    k: query,
    amazon_domain: "amazon.com",
    api_key: SERPAPI_KEY,
  });

  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 12000);

  try {
    const url = `https://serpapi.com/search.json?${params.toString()}`;
    const r = await fetch(url, { signal: controller.signal });

    if (!r.ok) {
      if (r.status === 429) {
        if (!softFail) {
          markSourceFailure("serpapi", "http_429");
          const h = getSourceHealth("serpapi");
          h.cooldownUntil = Math.max(Number(h.cooldownUntil || 0), Date.now() + 45 * 1000);
        }
        return [];
      }
      if (!softFail) markSourceFailure("serpapi", `http_${r.status}`);
      return [];
    }

    const data = await r.json();
    const raw = Array.isArray(data.organic_results) ? data.organic_results : [];

    let items = raw
      .map((it, idx) => {
        const rawPrice = it.price?.value ?? it.price ?? null;
        const price = rawPrice != null
          ? parseFloat(String(rawPrice).replace(/[^0-9.]/g, "")) || null
          : null;
        const link = it.link || (it.asin ? `https://www.amazon.com/dp/${it.asin}` : null);
        const normalized = normalizeItem({
          title: it.title,
          price,
          totalPrice: price,
          link,
          url: link,
          image: it.thumbnail,
          source: "Amazon",
        });
        return {
          ...normalized,
          link,
          url: link,
          buyLink: link,
          source: "Amazon",
          __fromMarketSearch: true,
          __serverRank: idx + 1,
        };
      })
      .filter((x) => x.title)
      .filter((x) => Number.isFinite(x.totalPrice) || Number.isFinite(x.price));

    items = dedupeSmart(items);
    markSourceSuccess("serpapi", Date.now() - startedAt);
    console.log("🛒 SERP AMAZON COUNT", { query, kept: items.length });
    return items.slice(0, 40);
  } catch (err) {
    if (!softFail) markSourceFailure("serpapi", err?.name === "AbortError" ? "timeout" : "exception");
    console.warn("⚠️ serpAmazon error:", err?.message || err, "query=", query);
    return [];
  } finally {
    clearTimeout(t);
  }
}

// -------------------- SERP: Scoped resale search (StockX / Poshmark / Depop / Mercari) --------------------
async function serpScopedSearch(query, site, opts = {}) {
  const { bypassCooldown = false, softFail = false, label = site } = opts || {};

  if (!SERPAPI_KEY) return [];
  if (process.env.DISABLE_SERP === "true") return [];
  if (!bypassCooldown && isSourceCoolingDown("serpapi")) return [];

  const startedAt = Date.now();

  const params = new URLSearchParams({
    engine: "google_shopping",
    q: `${query} site:${site}`,
    hl: "en",
    gl: "us",
    api_key: SERPAPI_KEY,
  });

  const controller = new AbortController();
  const t = setTimeout(() => controller.abort(), 12000);

  try {
    const url = `https://serpapi.com/search.json?${params.toString()}`;
    const r = await fetch(url, { signal: controller.signal });

    if (!r.ok) {
      if (r.status === 429) {
        if (!softFail) {
          markSourceFailure("serpapi", "http_429");
          const h = getSourceHealth("serpapi");
          h.cooldownUntil = Math.max(Number(h.cooldownUntil || 0), Date.now() + 45 * 1000);
        }
        return [];
      }
      if (!softFail) markSourceFailure("serpapi", `http_${r.status}`);
      return [];
    }

    const data = await r.json();
    const raw = [
      ...(Array.isArray(data.shopping_results) ? data.shopping_results : []),
      ...(Array.isArray(data.inline_shopping_results) ? data.inline_shopping_results : []),
    ];

    let items = raw
      .map((it, idx) => {
        const normalized = normalizeItem({
          ...it,
          link: it.link || it.product_link || it.product_page_url || it.url || null,
        });
        const fallbackLink =
          normalized.link || it.link || it.product_link || it.product_page_url || null;
        return {
          ...normalized,
          link: fallbackLink,
          url: fallbackLink,
          buyLink: fallbackLink,
          source: label,
          __fromMarketSearch: true,
          __serverRank: idx + 1,
        };
      })
      .filter((x) => x.title)
      .filter((x) => Number.isFinite(x.totalPrice) || Number.isFinite(x.price));

    items = dedupeSmart(items);
    markSourceSuccess("serpapi", Date.now() - startedAt);
    console.log(`🔍 SERP SCOPED [${label}]`, { query, kept: items.length });
    return items.slice(0, 30);
  } catch (err) {
    if (!softFail) markSourceFailure("serpapi", err?.name === "AbortError" ? "timeout" : "exception");
    console.warn(`⚠️ serpScopedSearch [${label}] error:`, err?.message || err);
    return [];
  } finally {
    clearTimeout(t);
  }
}

// -------------------- ETSY ROUTE --------------------
app.get("/search/etsy", async (req, res) => {
  const rawQuery = safeStr(req.query?.q, 220);
  const query = normalizeQuery(rawQuery);

  if (!query || !hasEtsyApi()) {
    return res.status(200).json([]);
  }

  const cacheKey = `etsy_priority|${query}`;
  const cached = SERP_CACHE.get(cacheKey);
  if (cached) return res.status(200).json(cached);

  try {
    const items = await withInflight(cacheKey, async () => {
      const variants = buildEtsyVariants(query);
      let merged = [];

      for (const q of variants) {
        const rows = await etsySearch(q);
        if (rows?.length) merged.push(...rows);
      }

      merged = dedupeSmart(merged);
      merged = filterRelevantListings(query, merged);
      merged = trimPriceOutliers(merged);
      merged = intuitionFilter(merged);
      merged = sortByAbsoluteCheapest(merged).slice(0, 60);

      return merged;
    });

    SERP_CACHE.set(cacheKey, items);
    return res.status(200).json(items);
  } catch {
    const fallback = SERP_CACHE.get(cacheKey);
    return res.status(200).json(fallback || []);
  }
});

