// Response schema:
//   { ok, category, index: { indexGrade, sampleCount, medianPrice, p25, p75, priceRange,
//     spread, avgPriceQuality, calibration, lastUpdated }, eligibility: { ready, grade, reason } }
// ─────────────────────────────────────────────────────────────────────────────
